#include <stdio.h>
#include <math.h>

int leastPrimeDivisor(int n) {
    if (n % 2 == 0) return 2;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return i;
    }
    return n;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < M; i++) {
            int type, L, R;
            scanf("%d %d %d", &type, &L, &R);
            if (type == 0) {
                for (int j = L - 1; j < R; j++) {
                    A[j] = A[j] / leastPrimeDivisor(A[j]);
                }
            } else {
                int max = 1;
                for (int j = L - 1; j < R; j++) {
                    max = (max > leastPrimeDivisor(A[j])) ? max : leastPrimeDivisor(A[j]);
                }
                printf("%d ", max);
            }
        }
        printf("\n");
    }
    return 0;
}

