import java.util.Scanner;
public class Main {
    public static int leastPrimeDivisor(int n) {
        if (n % 2 == 0) return 2;
        for (int i = 3; i * i <= n; i += 2) {
            if (n % i == 0) return i;
        }
        return n;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < M; i++) {
                int type = sc.nextInt();
                int L = sc.nextInt();
                int R = sc.nextInt();
                if (type == 0) {
                    for (int j = L - 1; j < R; j++) {
                        A[j] = A[j] / leastPrimeDivisor(A[j]);
                    }
                } else {
                    int max = 1;
                    for (int j = L - 1; j < R; j++) {
                        max = Math.max(max, leastPrimeDivisor(A[j]));
                    }
                    System.out.print(max + " ");
                }
            }
            System.out.println();
        }
    }
}

